SELECT id, username, phone, age 
FROM user 


        AND phone = #{phone}


        AND username LIKE CONCAT('%', #{username}, '%')


        AND age  >=  #{minAge}


        AND age  <=  #{maxAge}


ORDER BY create_time DESC
LIMIT #{pageSize} OFFSET #{offset}

SELECT COUNT(*)
FROM user 


        AND phone = #{phone}


        AND username LIKE CONCAT('%', #{username}, '%')


        AND age  >=  #{minAge}


        AND age  <= #{maxAge}
